installer-gui-script.script:
function tlsfix_os_check() {
    var v = system.version.ProductVersion;
    if ((system.compareVersions(v, '10.8.5') < 0) || (system.compareVersions(v, '10.9') >= 0)) {
        my.result.title = 'Unsupported Mac OS X Version';
        my.result.message = 'TLSFix requires Mac OS X 10.8.5 (Mountain Lion).\n\nThis Mac is running ' + v + '.';
        my.result.type = 'Fatal';
        return false;
    }
    return true;
}
